import { z } from "zod";

// Schema for the script generated by the LLM
export const ScriptItemSchema = z.object({
  textOverlay: z.string(),
  voiceoverText: z.string(),
  sceneImage: z.string(),
});

export type ScriptItem = z.infer<typeof ScriptItemSchema>;

// Schema for the final synchronized payload expected by the frontend (Remotion player)
export const SynchronizedScriptSchema = z.object({
  durationInFrames: z.number(),
  textOverlay: z.string(),
  voiceoverText: z.string(),
  audioUrl: z.string(),
  sceneImage: z.string(),
});

export type SynchronizedScript = z.infer<typeof SynchronizedScriptSchema>;

export type TTSAudioResult = {
  audioUrl: string;
  durationInSeconds: number;
};

/**
 * 1. Accepts an array of strings (voiceoverText).
 * 2. Makes an async call to a TTS API (mocked for MVP).
 * 3. Returns dummy audio URLs and a hardcoded duration of 3 seconds.
 */
export async function generateTTSAudio(voiceoverTexts: string[]): Promise<TTSAudioResult[]> {
  // CRITICAL: MVP Mock Implementation
  // Later we can switch to OpenAI/ElevenLabs SDK or use native Next.js `fetch`.
  const promises = voiceoverTexts.map(async (text) => {
    // Simulate slight network delay for realism
    await new Promise((resolve) => setTimeout(resolve, 300));

    return {
      audioUrl: "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3", // Dummy URL
      durationInSeconds: 3, // Hardcoded 3 seconds
    };
  });

  return Promise.all(promises);
}

