/**
 * 4. Middleware function that takes the LLM's JSON script array and TTS audio URLs.
 * Maps audio URLs back into the JSON array objects, creating a `SynchronizedScript` type.
 */
export function synchronizeScriptAndAudio(
  scriptItems: ScriptItem[],
  audioResults: TTSAudioResult[],
  fps: number = 30
): SynchronizedScript[] {
  if (scriptItems.length !== audioResults.length) {
    throw new Error("Mismatch: The number of script items does not match the TTS audio results.");
  }

  return scriptItems.map((item, index) => {
    const audioResult = audioResults[index];

    // Calculate duration in frames: durationInSeconds * framesPerSecond
    const durationInFrames = Math.ceil(audioResult.durationInSeconds * fps);

    return {
      durationInFrames,
      textOverlay: item.textOverlay,
      voiceoverText: item.voiceoverText,
      audioUrl: audioResult.audioUrl,
      sceneImage: item.sceneImage,
    };
  });
}

/**
 * 5. Main orchestration function to generate the final synchronized payload 
 * to be consumed by the frontend.
 */
export async function processMediaPipeline(items: ScriptItem[], fps: number = 30): Promise<SynchronizedScript[]> {
  // Extract all voiceover strings
  const voiceoverTexts = items.map((item) => item.voiceoverText);

  // Generate TTS Audio (currently the MVP mock)
  const audioResults = await generateTTSAudio(voiceoverTexts);

  // Map everything back together into a final payload
  return synchronizeScriptAndAudio(items, audioResults, fps);
}
